/**
 * Call getSign directly and write result to a file
 */

Java.perform(function () {
    console.log('Starting direct call test...');

    try {
        var AppUtils = Java.use('com.newreading.goodreels.utils.AppUtils');

        // Test with known parameters
        var timestamp = '1769855063192';
        var path = '/home/index';

        console.log('Calling getSign with:');
        console.log('  timestamp: ' + timestamp);
        console.log('  path: ' + path);

        var result = AppUtils.getSign(timestamp, path);

        console.log('\n========================================');
        console.log('SIGN GENERATED BY APP:');
        console.log(result);
        console.log('========================================\n');

        // Compare with captured sign
        var capturedSign = '';

        console.log('Match with captured: ' + (result === capturedSign ? 'YES!' : 'NO'));

        // Also get device IDs to understand what's being used
        console.log('\nDevice parameters used:');
        console.log('  GAID: ' + AppUtils.getGAID());
        console.log('  AndroidID: ' + AppUtils.getAndroidID());
        console.log('  PackageName: ' + AppUtils.getPkna());

    } catch (e) {
        console.log('Error: ' + e.message);
        console.log(e.stack);
    }
});
